17	// JSON envelopes: reproduce every captured json body from its parsed slots.
18	// ---------------------------------------------------------------------------
19	
20	fn check_all_envelopes(manifest_json: &str) -> (usize, usize) {
21	    let entries: Vec<Value> = serde_json::from_str(manifest_json).unwrap();
22	    let (mut content, mut redirect) = (0usize, 0usize);
23	    for e in &entries {
24	        let body = e["body"].as_str().unwrap();
25	        let parsed: Value = serde_json::from_str(body).unwrap();
26	        let obj = parsed.as_object().unwrap();
27	        if let Some(r) = obj.get("redirect") {
28	            let got = render_redirect(r.as_str().unwrap());
29	            assert_eq!(got, body, "redirect envelope mismatch for {}", e["route"]);
30	            redirect += 1;
31	        } else {
32	            let html = obj["html"].as_str().unwrap();
33	            let title = obj["title"].as_str().unwrap();
34	            let got = render_content(html, title);
35	            assert_eq!(got, body, "content envelope mismatch for {}", e["route"]);
36	            content += 1;
37	        }
38	    }
39	    (content, redirect)
40	}
