1	//! JSON response envelopes for the `main/*` (and `method/*`, `autoprove/*`)
2	//! AJAX handlers.
3	//!
4	//! Observed: every `kind=json` response body is one of exactly two compact
5	//! JSON objects, with keys in this order and no insignificant whitespace:
6	//!   * content:  `{"html":<string>,"title":<string>}`
7	//!   * redirect: `{"redirect":<string>}`
8	//! There is no trailing newline. Non-ASCII is emitted as literal UTF-8 (no
9	//! `\uXXXX`), and `/ < > &` are NOT backslash/entity escaped inside the JSON
10	//! string — i.e. standard JSON string escaping (only `" \` and control chars).
11	//! `serde_json`'s default serialization reproduces this exactly.
12	
13	use serde::Serialize;
14	
15	/// A content pane response: rendered HTML plus the pane title.
16	#[derive(Serialize)]
17	pub struct Content<'a> {
18	    pub html: &'a str,
19	    pub title: &'a str,
20	}
21	
22	/// A redirect response instructing the client to navigate to `redirect`.
23	#[derive(Serialize)]
24	pub struct Redirect<'a> {
25	    pub redirect: &'a str,
26	}
27	
28	/// Serialize `{"html":..,"title":..}` exactly as the web layer does.
29	pub fn render_content(html: &str, title: &str) -> String {
30	    serde_json::to_string(&Content { html, title }).expect("Content serializes")
31	}
32	
33	/// Serialize `{"redirect":..}` exactly as the web layer does.
34	pub fn render_redirect(path: &str) -> String {
35	    serde_json::to_string(&Redirect { redirect: path }).expect("Redirect serializes")
36	}
37	
38	#[cfg(test)]
39	mod tests {
40	    use super::*;
41	
42	    #[test]
43	    fn content_envelope_shape() {
44	        assert_eq!(
45	            render_content("this is a mistake<br/>\n", "Lemma: exec"),
46	            r#"{"html":"this is a mistake<br/>\n","title":"Lemma: exec"}"#
47	        );
48	    }
49	
50	    #[test]
51	    fn redirect_envelope_shape() {
52	        assert_eq!(
53	            render_redirect("/thy/trace/4/overview/proof/exec/_"),
54	            r#"{"redirect":"/thy/trace/4/overview/proof/exec/_"}"#
55	        );
56	    }
57	
58	    #[test]
59	    fn keeps_literal_utf8_and_unescaped_angle_brackets() {
60	        let s = render_content("<span>∃</span>", "t");
61	        assert!(s.contains("<span>∃</span>"), "got {s}");
62	        assert!(!s.contains("\\u"), "should not \\u-escape: {s}");
63	    }
64	}
