1	//! Error response pages.
2	//!
3	//! Observed by live probing: a request that does not match any route (unknown
4	//! handler, non-existent theory index, or a path segment the router rejects
5	//! such as a URL-encoded `%23`) returns HTTP 404 with a full HTML page. The
6	//! page reuses the standard `<head>` link set and the standard page tail; its
7	//! body is just the loading bar, an `<h1>Not Found</h1>`, and the echoed
8	//! request path in a `<p>`. The echoed path is HTML-escaped.
9	
10	use crate::escape::html_escape;
11	use crate::notfound_template::NOT_FOUND;
12	
13	/// Render the 404 Not Found page for a given (already percent-encoded) request
14	/// path. The path is HTML-escaped before being echoed into the body.
15	pub fn render_not_found(request_path: &str) -> String {
16	    NOT_FOUND.replace("§PATH§", &html_escape(request_path))
17	}
18	
19	#[cfg(test)]
20	mod tests {
21	    use super::*;
22	
23	    #[test]
24	    fn not_found_echoes_path() {
25	        let p = render_not_found("/thy/trace/1/main/nope");
26	        assert!(p.contains("<title>Not Found</title>"));
27	        assert!(p.contains("<h1>Not Found</h1>\n<p>/thy/trace/1/main/nope</p>"));
28	        assert!(p.ends_with("</body></html>"));
29	    }
30	}
