1	//! HTML entity escaping used by the web layer.
2	//!
3	//! Observed escape set (from oracle output): the five characters
4	//! `& < > " '` map to `&amp; &lt; &gt; &quot; &#39;` respectively; every other
5	//! byte (including all non-ASCII UTF-8, e.g. the logic operators the prover
6	//! emits) passes through unchanged. Escaping is applied left-to-right in a
7	//! single pass, and `&` is handled first so already-produced entities are not
8	//! double-escaped.
9	//!
10	//! Witnesses:
11	//!   `'` -> `&#39;`   (the "'smart' heuristic" comment in proof-method pages)
12	//!   `<`,`>` -> `&lt;`,`&gt;`   (pair terms `<x.1, x.2>` in the signature view)
13	//!   `"` -> `&quot;`  (loaded-from path, and lemma text in the edit form)
14	//!   `&` -> `&amp;`   (a literal `&` inside a lemma formula)
15	
16	/// Escape a plain string into HTML text, matching the web layer's entity set.
17	pub fn html_escape(s: &str) -> String {
18	    let mut out = String::with_capacity(s.len());
19	    for c in s.chars() {
20	        match c {
21	            '&' => out.push_str("&amp;"),
22	            '<' => out.push_str("&lt;"),
23	            '>' => out.push_str("&gt;"),
24	            '"' => out.push_str("&quot;"),
25	            '\'' => out.push_str("&#39;"),
26	            other => out.push(other),
27	        }
28	    }
29	    out
30	}
31	
32	#[cfg(test)]
33	mod tests {
34	    use super::*;
35	
36	    #[test]
37	    fn escapes_the_five_special_characters() {
38	        assert_eq!(html_escape("a<b>c"), "a&lt;b&gt;c");
39	        assert_eq!(html_escape("x & y"), "x &amp; y");
40	        assert_eq!(html_escape("say \"hi\""), "say &quot;hi&quot;");
41	        assert_eq!(html_escape("'smart'"), "&#39;smart&#39;");
42	    }
43	
44	    #[test]
45	    fn passes_through_non_ascii_unchanged() {
46	        // Prover-emitted logic operators are not part of the escape set.
47	        assert_eq!(html_escape("∃ x ▶₀ #i"), "∃ x ▶₀ #i");
48	    }
49	
50	    #[test]
51	    fn does_not_double_escape() {
52	        assert_eq!(html_escape("<&>"), "&lt;&amp;&gt;");
53	    }
54	}
