1	//! The proof-script (west) pane markup embedded in the theory-view page and in
2	//! the `main/*` navigation.
3	//!
4	//! ## Line model (observed)
5	//! The pane is a flat sequence of logical lines. Rendering emits each line's
6	//! text followed by the literal `"<br/>\n"`, and finally a single trailing
7	//! space `" "`. A blank line is an element whose text is empty (yielding a lone
8	//! `"<br/>\n"`). This one rule reproduces the exact blank-line spacing of both
9	//! the no-lemma and multi-lemma captures.
10	//!
11	//! ## Element order
12	//! 1. `theory NAME begin` header line
13	//! 2. one blank + link line per theory item, in order: Message theory, rules,
14	//!    Tactic(s), Raw sources, Refined sources
15	//! 3. one blank + the `add lemma` link for position `<first>`
16	//! 4. for each lemma: one blank, the lemma's body lines, one blank, the lemma's
17	//!    trailing `add lemma` link (targeting that lemma's name)
18	//! 5. one blank + `end`
19	//!
20	//! When there are zero lemmas, step 4 contributes nothing, which leaves TWO
21	//! blank lines between the `<first>` add-link and `end` (matching the capture).
22	//!
23	//! ## Slots that come from the prover (opaque here)
24	//! The lemma declaration HTML (`decl_html`: the pretty-printed `lemma NAME:` +
25	//! quantifier + formula, already entity-escaped and wrapped in `hl_operator`
26	//! spans), the rules label/count, the sources descriptions, and — for a solved
27	//! proof — each proof step's method HTML and case names. Everything else (the
28	//! anchors, keywords, indentation, links) is generated here.
29	//!
30	//! ## Indices
31	//! Every internal href uses the resolved numeric theory index, never `#`.
32	
33	/// A theory item shown as a top link in the proof-script pane.
34	pub enum Item<'a> {
35	    /// `Message theory` link.
36	    Message,
37	    /// Multiset rewriting rules link. `label` is the prover's wording
38	    /// (`"Multiset rewriting rules"`, or with `" and restrictions"`), `count`
39	    /// the rule count.
40	    Rules { label: &'a str, count: usize },
41	    /// `Tactic(s)` link.
42	    Tactic,
43	    /// `Raw sources` link; `desc` e.g. `"4 cases, deconstructions complete"`.
44	    RawSources { desc: &'a str },
45	    /// `Refined sources` link; note the label carries a trailing space.
46	    RefinedSources { desc: &'a str },
47	}
48	
49	/// How a lemma's proof is displayed.
50	pub enum Proof<'a> {
51	    /// Unproven: a single `by sorry` proof-step line.
52	    Sorry,
53	    /// A solved/partial proof rendered as an explicit list of proof lines.
54	    Steps(Vec<ProofLine<'a>>),
55	}
56	
57	/// One line of a rendered proof tree.
58	pub enum ProofLine<'a> {
59	    /// A proof-method step (an applied method or a leaf such as `SOLVED`).
60	    Step {
61	        depth: usize,
62	        /// Status class, e.g. `"hl_good"`.
63	        status: &'a str,
64	        /// Full href, e.g. `/thy/trace/3/main/proof/exec/_/B_2`.
65	        href: String,
66	        /// Prover method HTML, e.g. `<span class="hl_keyword">simplify</span>`.
67	        method_html: &'a str,
68	        /// Annotation shown in the remove-step anchor (usually empty).
69	        annotation: &'a str,
70	        /// Whether the line is prefixed with a wrapped `by ` keyword.
71	        by: bool,
72	    },
73	    /// A `case NAME` header.
74	    Case {
75	        depth: usize,
76	        status: &'a str,
77	        name: &'a str,
78	    },
79	    /// A `next` separator between sibling cases.
80	    Next { depth: usize, status: &'a str },
81	    /// A `qed` closing a case block.
82	    Qed { depth: usize, status: &'a str },
83	}
84	
85	/// A single lemma block.
86	pub struct Lemma<'a> {
87	    /// Lemma name (used in the edit/delete/add/proof links).
88	    pub name: &'a str,
89	    /// Opaque prover-produced declaration HTML (`lemma NAME:` + formula).
90	    pub decl_html: &'a str,
91	    /// Proof display.
92	    pub proof: Proof<'a>,
93	}
94	
95	/// The whole proof-script pane input.
96	pub struct Overview<'a> {
97	    pub theory_name: &'a str,
98	    pub index: u64,
99	    pub items: Vec<Item<'a>>,
100	    pub lemmas: Vec<Lemma<'a>>,
101	}
102	
103	fn indent(depth: usize) -> String {
104	    "&nbsp;&nbsp;".repeat(depth)
105	}
106	
107	/// Render one proof-tree line (public so the line grammar can be unit-tested).
108	pub fn render_proof_line(line: &ProofLine) -> String {
109	    match line {
110	        ProofLine::Step {
111	            depth,
112	            status,
113	            href,
114	            method_html,
115	            annotation,
116	            by,
117	        } => {
118	            let ind = indent(*depth);
119	            let by_prefix = if *by {
120	                format!(r#"<span class="{status}"><span class="hl_keyword">by</span> </span>"#)
121	            } else {
122	                String::new()
123	            };
124	            format!(
125	                r#"{ind}{by_prefix}<a class="internal-link proof-step {status}" href="{href}">{method_html}</a><a class="internal-link remove-step" href="{href}">{annotation}</a>"#
126	            )
127	        }
128	        ProofLine::Case {
129	            depth,
130	            status,
131	            name,
132	        } => format!(
133	            r#"{}<span class="{status}"><span class="hl_keyword">case</span> {name}</span>"#,
134	            indent(*depth)
135	        ),
136	        ProofLine::Next { depth, status } => format!(
137	            r#"{}<span class="{status}"><span class="hl_keyword">next</span></span>"#,
138	            indent(*depth)
139	        ),
140	        ProofLine::Qed { depth, status } => format!(
141	            r#"{}<span class="{status}"><span class="hl_keyword">qed</span></span>"#,
142	            indent(*depth)
143	        ),
144	    }
145	}
